// Parse Telegram's callback_query update.
// Expected callback_data format: 'approve:<record_id>' or 'reject:<record_id>'
const body = $json.body || $json;
const cb = body && body.callback_query;
if (!cb || !cb.data) {
  // Not a callback_query (Telegram also sends other update types) — exit quietly.
  return [];
}
const [decision, recordId] = cb.data.split(':');
if (!recordId || (decision !== 'approve' && decision !== 'reject')) {
  return [];
}
const from = cb.from || {};
const reviewerName = ((from.first_name || '') + ' ' + (from.last_name || '')).trim() || from.username || 'reviewer';
const nowIST = new Date().toLocaleString('en-IN', { timeZone: 'Asia/Kolkata', hour12: false, dateStyle: 'short', timeStyle: 'short' });

return [{ json: {
  decision,
  recordId,
  reviewerName,
  nowIST,
  callback_id: cb.id,
  message_id:  cb.message ? cb.message.message_id : null,
  chat_id:     cb.message && cb.message.chat ? cb.message.chat.id : null,
  original_text: cb.message ? (cb.message.text || '') : ''
}}];

